const targetWeekId = $('Set week_id').first().json.week_id;
const items = $input.all();

const approvedPosts = items
  .map(item => item.json)
  .filter(row =>
    row.week_id === targetWeekId &&
    String(row.approval_status || '').toLowerCase() === 'approved'
  );

if (approvedPosts.length === 0) {
  throw new Error(`No approved posts found for week_id=${targetWeekId}`);
}

return [
  {
    json: {
      week_id: targetWeekId,
      approved_posts: approvedPosts
    }
  }
];

const weekId = $json.week_id;
const posts = $json.approved_posts || [];

const sortedPosts = posts.sort((a, b) => Number(a.post_number) - Number(b.post_number));

let html = `
<h2>✅ Approved Posts Ready to Schedule</h2>
<p><strong>Week:</strong> ${weekId}</p>
<hr/>
`;

for (const post of sortedPosts) {
  const assetIds = (post.asset_ids || '').split(',').map(s => s.trim()).filter(Boolean);

  let imagesHtml = '';
  for (const id of assetIds) {
    const imgUrl = `https://drive.google.com/uc?export=view&id=${id}`;
    imagesHtml += `
      <img src="${imgUrl}" style="max-width:300px; margin:10px 0; border-radius:6px;" />
      <br/>
    `;
  }

  html += `
    <div style="margin-bottom:40px;">
      <h3>Post ${post.post_number}</h3>

      ${imagesHtml}

      <p><strong>Content Type:</strong> ${post.content_type}</p>
      <p><strong>Platforms:</strong> ${post.platform || ''}</p>
      <p><strong>Scheduled Date:</strong> ${post.scheduled_date || ''}</p>
      <p><strong>Scheduled Time:</strong> ${post.scheduled_time || ''}</p>

      <p><strong>Caption:</strong><br/>
      ${post.caption || ''}</p>

      <p><strong>Hashtags:</strong><br/>
      ${post.hashtags || ''}</p>

      <p><strong>Notes:</strong><br/>
      ${post.notes || ''}</p>
    </div>
    <hr/>
  `;
}

return [
  {
    json: {
      subject: `Approved Posts Ready to Schedule — ${weekId}`,
      html,
      text: `Approved posts ready to schedule for ${weekId}`
    }
  }
];
